<template>
  <div class="space-y-8">
    <div class="bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl p-8 sm:p-12 text-white shadow-lg relative overflow-hidden">
      <!-- Decorative circles -->
      <div class="absolute top-0 right-0 -mr-16 -mt-16 w-64 h-64 rounded-full bg-white opacity-10"></div>
      <div class="absolute bottom-0 right-32 -mb-16 w-48 h-48 rounded-full bg-white opacity-10"></div>
      
      <div class="relative z-10">
        <h2 class="text-3xl sm:text-5xl font-extrabold mb-4 drop-shadow-sm">Agende sua consulta</h2>
        <p class="text-lg sm:text-xl text-blue-100 max-w-2xl font-medium">
          Escolha o serviço desejado abaixo e marque seu horário com facilidade e rapidez.
        </p>
      </div>
    </div>
    
    <div class="flex items-center justify-between pb-2 border-b">
       <h3 class="text-2xl font-bold text-gray-800">Serviços Disponíveis</h3>
       <span class="text-gray-500 font-medium bg-gray-100 px-3 py-1 rounded-full text-sm">
         {{ servicos.length }} Ativos
       </span>
    </div>

    <!-- Lista -->
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
       <div v-if="loading" v-for="i in 3" :key="i" class="bg-white border rounded-xl p-6 h-40 animate-pulse">
          <div class="h-6 bg-gray-200 rounded w-1/2 mb-4"></div>
          <div class="h-4 bg-gray-200 rounded w-1/3 mb-2"></div>
          <div class="h-4 bg-gray-200 rounded w-1/4"></div>
       </div>

       <div v-else-if="servicos.length === 0" class="col-span-full py-12 text-center text-gray-400 bg-gray-50 rounded-xl border border-dashed">
          <p class="text-lg font-medium">Nenhum serviço disponível no momento.</p>
       </div>

       <div v-else v-for="servico in servicos" :key="servico.id" 
            class="bg-white rounded-2xl p-6 shadow-sm border border-gray-100 hover:shadow-xl hover:border-blue-200 transition-all duration-300 group flex flex-col justify-between relative overflow-hidden">
          
          <div class="absolute top-0 right-0 w-16 h-16 bg-blue-50 rounded-bl-full -mr-8 -mt-8 transition-transform group-hover:scale-150"></div>
          
          <div class="relative z-10 mb-6">
             <h3 class="font-bold text-xl text-gray-900 group-hover:text-blue-600 transition-colors mb-2">{{ servico.nome }}</h3>
             <div class="flex items-center text-gray-500 text-sm space-x-4">
                <span class="flex items-center"><svg class="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>{{ servico.duracaoMinutos }} min</span>
             </div>
          </div>

          <div class="relative z-10 flex items-center justify-between mt-auto">
             <div class="flex flex-col">
               <span class="text-xs font-semibold text-gray-400 uppercase tracking-wider">Investimento</span>
               <span class="text-2xl font-extrabold text-gray-800">{{ servico.moeda }} {{ servico.preco?.toFixed(2) }}</span>
             </div>
             <NuxtLink :to="`/agendar/${servico.id}`" 
                class="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold shadow-md shadow-blue-500/30 hover:bg-blue-700 hover:shadow-blue-600/40 active:scale-95 transition-all">
               Agendar
             </NuxtLink>
          </div>
       </div>
    </div>
  </div>
</template>

<script setup lang="ts">
const servicos = ref<any[]>([])
const loading = ref(true)

const fetchServicos = async () => {
  try {
    const res = await $fetch<any[]>('http://localhost:8080/api/public/servicos')
    servicos.value = res
  } catch (e) {
    console.error(e)
  } finally {
    loading.value = false
  }
}

onMounted(() => {
  fetchServicos()
})
</script>
